        }
        return parent[u];
    }

    function union(u: number, v: number): boolean {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) return false;
        parent[rootV] = rootU;
        return true;
    }

    for (const [u, v, w] of edges) {
        if (w <= X) {
            union(u, v);
        }
    }

    const roots = new Set<number>();
    for (let i = 0; i < n; i++) {
        roots.add(find(i));
    }

    return roots.size;
}
